/**
 * Files App UI - HomeChannel
 * Full file browser ES module loaded in sandboxed iframe.
 * Communicates with the parent frame (which owns the datachannel) via postMessage:
 *   Send:    window.parent.postMessage({ type: 'channel:send', data: jsonString }, '*')
 *   Receive: window.addEventListener('message', evt => { if (evt.data.type === 'channel:message') ... })
 */

