document.head.appendChild(style);

// ── SVG icon helpers ──────────────────────────────────────────────────────────
const ICONS = {
  folder: '<path d="M10 4H4c-1.1 0-2 .9-2 2v12c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V8c0-1.1-.9-2-2-2h-8l-2-2z"/>',
  file: '<path d="M14 2H6c-1.1 0-2 .9-2 2v16c0 1.1.9 2 2 2h12c1.1 0 2-.9 2-2V8l-6-6zm2 16H8v-2h8v2zm0-4H8v-2h8v2zm-3-5V3.5L18.5 9H13z"/>',
  back: '<path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>',
  newFolder: '<path d="M20 6h-8l-2-2H4c-1.1 0-2 .9-2 2v12c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V8c0-1.1-.9-2-2-2zm-1 8h-3v3h-2v-3h-3v-2h3V9h2v3h3v2z"/>',
  upload: '<path d="M9 16h6v-6h4l-7-7-7 7h4zm-4 2h14v2H5z"/>',
  download: '<path d="M19 9h-4V3H9v6H5l7 7 7-7zM5 18v2h14v-2H5z"/>',
  trash: '<path d="M6 19c0 1.1.9 2 2 2h8c1.1 0 2-.9 2-2V7H6v12zM19 4h-3.5l-1-1h-5l-1 1H5v2h14V4z"/>',
  spinner: '<path d="M12 4V1L8 5l4 4V6c3.31 0 6 2.69 6 6 0 1.01-.25 1.97-.7 2.8l1.46 1.46C19.54 15.03 20 13.57 20 12c0-4.42-3.58-8-8-8zm0 14c-3.31 0-6-2.69-6-6 0-1.01.25-1.97.7-2.8L5.24 7.74C4.46 8.97 4 10.43 4 12c0 4.42 3.58 8 8 8v3l4-4-4-4v3z"/>',
  ok: '<path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm-2 15l-5-5 1.41-1.41L10 14.17l7.59-7.59L19 8l-9 9z"/>',
  err: '<path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-2h2v2zm0-4h-2V7h2v6z"/>',
  info: '<path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-6h2v6zm0-8h-2V7h2v2z"/>',
};

function svg(name, color = 'currentColor') {
  return `<svg viewBox="0 0 24 24" fill="${color}">${ICONS[name]}</svg>`;
}

// ── DOM ───────────────────────────────────────────────────────────────────────
document.body.innerHTML = `
<div id="app">
  <div id="toolbar">
    <span class="title">📁 Files</span>
    <button class="tb-btn" id="btn-back" disabled title="Go up">${svg('back')} Back</button>
    <button class="tb-btn" id="btn-new-folder" title="New folder">${svg('newFolder')} New Folder</button>
    <button class="tb-btn" id="btn-upload" title="Upload files">${svg('upload')} Upload</button>
  </div>
  <div id="breadcrumb"></div>
  <div id="file-area">
    <div id="file-list"></div>
  </div>
</div>

<div id="loading"><svg class="spinner-svg" viewBox="0 0 24 24">${ICONS.spinner}</svg> Loading…</div>
<div id="toast" class="hidden"></div>
<div id="modal-bg"><div id="modal"></div></div>
<input type="file" id="file-input" multiple style="display:none">
`;

const elLoading = document.getElementById('loading');
const elToast = document.getElementById('toast');
const elModalBg = document.getElementById('modal-bg');
const elModal = document.getElementById('modal');
const elBreadcrumb = document.getElementById('breadcrumb');
const elFileList = document.getElementById('file-list');
const elBtnBack = document.getElementById('btn-back');
const elBtnNewFolder = document.getElementById('btn-new-folder');
const elBtnUpload = document.getElementById('btn-upload');
const elFileInput = document.getElementById('file-input');

// ── State ─────────────────────────────────────────────────────────────────────
const state = {
  currentPath: '',
  files: [],
  pending: new Map(),
  uploads: new Map(),  // requestId → { name, resolve }
  nextId: 1,
};

// ── Helpers ───────────────────────────────────────────────────────────────────
function esc(text) {
  const d = document.createElement('div');
  d.textContent = String(text);
  return d.innerHTML;
}

function fmtSize(bytes) {
  if (bytes == null) return '';
  if (bytes === 0) return '0 B';
  const units = ['B', 'KB', 'MB', 'GB'];
  const i = Math.min(Math.floor(Math.log(bytes) / Math.log(1024)), units.length - 1);
  return (bytes / Math.pow(1024, i)).toFixed(i === 0 ? 0 : 1) + ' ' + units[i];
}

function fmtDate(ms) {
  if (!ms) return '';
  const d = new Date(ms);
  const now = new Date();
  const diff = now - d;
  if (diff < 86400000) return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  if (diff < 604800000) return d.toLocaleDateString([], { weekday: 'short' }) + ' ' + d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  return d.toLocaleDateString();
}

let toastTimer = null;
function toast(msg, type = 'info') {
  const colors = { error: '#e55', success: '#51cf66', info: '#667eea' };
  const icons = { error: 'err', success: 'ok', info: 'info' };
  elToast.innerHTML = `${svg(icons[type], colors[type])}<span>${esc(msg)}</span>`;
  elToast.className = type;
  clearTimeout(toastTimer);
  toastTimer = setTimeout(() => elToast.classList.add('hidden'), 5000);
}

function setLoading(on) {
  elLoading.classList.toggle('hidden', !on);
}

// ── Modal ─────────────────────────────────────────────────────────────────────
function showModal(html) {
  elModal.innerHTML = html;
  elModalBg.classList.add('active');
}
function hideModal() {
  elModalBg.classList.remove('active');
  elModal.innerHTML = '';
}
elModalBg.addEventListener('click', e => { if (e.target === elModalBg) hideModal(); });

// ── Channel communication ─────────────────────────────────────────────────────
function sendRequest(operation, params = {}) {
  return new Promise((resolve, reject) => {
    const requestId = `r${state.nextId++}_${Date.now()}`;
    state.pending.set(requestId, { resolve, reject });
    const msg = JSON.stringify({ requestId, operation, params });
    window.parent.postMessage({ type: 'channel:send', data: msg }, '*');
    // 30s timeout
    setTimeout(() => {
      if (state.pending.has(requestId)) {
        state.pending.delete(requestId);
        reject(new Error('Request timed out'));
      }
    }, 30000);
  });
}

window.addEventListener('message', evt => {
  if (!evt.data) return;
  const { type } = evt.data;

  if (type === 'channel:message') {
    try {
      const data = JSON.parse(evt.data.data);
      if (data.requestId && state.pending.has(data.requestId)) {
        const { resolve, reject } = state.pending.get(data.requestId);
        state.pending.delete(data.requestId);
        if (data.success) resolve(data.result);
        else reject(new Error(data.error || 'Operation failed'));
      }
    } catch (_) {}
  } else if (type === 'download:progress') {
    // (optional future progress bar)
  } else if (type === 'download:done') {
    toast('Downloaded: ' + evt.data.name, 'success');
    setLoading(false);
  } else if (type === 'upload:done') {
    const up = state.uploads.get(evt.data.requestId);
    if (up) {
      state.uploads.delete(evt.data.requestId);
      if (evt.data.success !== false) toast('Uploaded: ' + up.name, 'success');
      else toast('Upload failed: ' + (evt.data.error || 'Unknown error'), 'error');
      up.resolve();
    }
  }
});

// ── File operations ───────────────────────────────────────────────────────────
async function listDir(path) {
  setLoading(true);
  try {
    const result = await sendRequest('listDirectory', { path });
    state.currentPath = path;
    state.files = result.items || [];
    renderBreadcrumb();
    renderFileList();
  } catch (err) {
    toast('Failed to list directory: ' + err.message, 'error');
  } finally {
    setLoading(false);
  }
}

async function downloadFile(filePath, name) {
  setLoading(true);
  // Delegate to parent frame — sandboxed iframe cannot trigger browser downloads.
  // Parent frame will stream the file via the datachannel and trigger a.download.
  window.parent.postMessage({ type: 'channel:download', path: filePath, name }, '*');
  // Loading is cleared when parent posts 'download:done'
}

async function deleteItem(filePath, type, name) {
  const op = type === 'directory' ? 'deleteDirectory' : 'deleteFile';
  showModal(`
    <h2>Delete ${type === 'directory' ? 'Folder' : 'File'}?</h2>
    <p>Are you sure you want to delete <strong>${esc(name)}</strong>?</p>
    ${type === 'directory' ? '<p style="color:#e55;margin-top:.4rem;font-size:.85rem;">The folder must be empty.</p>' : ''}
    <div class="modal-actions">
      <button class="btn btn-secondary" id="m-cancel">Cancel</button>
      <button class="btn btn-danger" id="m-confirm">Delete</button>
    </div>
  `);
  document.getElementById('m-cancel').onclick = hideModal;
  document.getElementById('m-confirm').onclick = async () => {
    hideModal();
    setLoading(true);
    try {
      await sendRequest(op, { path: filePath });
      toast(`${type === 'directory' ? 'Folder' : 'File'} deleted`, 'success');
      await listDir(state.currentPath);
    } catch (err) {
      toast('Delete failed: ' + err.message, 'error');
    } finally {
      setLoading(false);
    }
  };
}

async function uploadFile(file) {
  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const requestId = `ul_${state.nextId++}_${Date.now()}`;
      const filePath = state.currentPath ? state.currentPath + '/' + file.name : file.name;
      state.uploads.set(requestId, { name: file.name, resolve });
      // Signal upload start (server allocates write stream)
      window.parent.postMessage({ type: 'channel:upload:start', requestId, path: filePath, size: file.size }, '*');
      // Stream chunks as transferred ArrayBuffers
      const buf = e.target.result;
      const CHUNK = 65536;
      for (let off = 0; off < buf.byteLength; off += CHUNK) {
        const slice = buf.slice(off, off + CHUNK);
        window.parent.postMessage({ type: 'channel:chunk', requestId, buffer: slice }, '*', [slice]);
      }
      // Signal end; parent will send FRAME_END to server
      window.parent.postMessage({ type: 'channel:upload:end', requestId }, '*');
      // upload:done comes back asynchronously via 'message' listener
    };
    reader.onerror = () => {
      toast('Could not read file: ' + file.name, 'error');
      resolve();
    };
    reader.readAsArrayBuffer(file);
  });
}

// ── Render ────────────────────────────────────────────────────────────────────
function renderBreadcrumb() {
  const parts = state.currentPath ? state.currentPath.split('/').filter(Boolean) : [];
  elBtnBack.disabled = parts.length === 0;

  let html = `<span class="bc-item ${parts.length === 0 ? 'active' : ''}" data-path="">🏠 Home</span>`;
  parts.forEach((part, i) => {
    const p = parts.slice(0, i + 1).join('/');
    const isLast = i === parts.length - 1;
    html += `<span class="bc-sep">/</span><span class="bc-item ${isLast ? 'active' : ''}" data-path="${esc(p)}">${esc(part)}</span>`;
  });
  elBreadcrumb.innerHTML = html;
  elBreadcrumb.querySelectorAll('.bc-item:not(.active)').forEach(el => {
    el.addEventListener('click', () => listDir(el.dataset.path));
  });
}

function renderFileList() {
  if (state.files.length === 0) {
    elFileList.innerHTML = `<div class="empty">${svg('folder')}<p>This folder is empty</p></div>`;
    return;
  }

  const sorted = [...state.files].sort((a, b) => {
    if (a.type !== b.type) return a.type === 'directory' ? -1 : 1;
    return a.name.localeCompare(b.name);
  });

  elFileList.innerHTML = '';
  for (const item of sorted) {
    const fullPath = state.currentPath ? state.currentPath + '/' + item.name : item.name;
    const isDir = item.type === 'directory';

    const row = document.createElement('div');
    row.className = 'file-row';
    row.innerHTML = `
      <div class="icon">${svg(isDir ? 'folder' : 'file', isDir ? '#FFA726' : '#667eea')}</div>
      <div class="name" title="${esc(item.name)}">${esc(item.name)}</div>
      <div class="size">${isDir ? '—' : fmtSize(item.size)}</div>
      <div class="date">${fmtDate(item.modified)}</div>
      <div class="actions">
        ${!isDir ? `<button class="row-btn dl" title="Download">${svg('download')}</button>` : ''}
        <button class="row-btn del" title="Delete">${svg('trash')}</button>
      </div>
    `;

    // Open directory on click / double-click
    if (isDir) {
      row.addEventListener('click', e => {
        if (!e.target.closest('button')) listDir(fullPath);
      });
    }

    const dlBtn = row.querySelector('.dl');
    if (dlBtn) dlBtn.addEventListener('click', e => { e.stopPropagation(); downloadFile(fullPath, item.name); });

    const delBtn = row.querySelector('.del');
    delBtn.addEventListener('click', e => { e.stopPropagation(); deleteItem(fullPath, item.type, item.name); });

    elFileList.appendChild(row);
  }
}

// ── Event handlers ────────────────────────────────────────────────────────────
elBtnBack.addEventListener('click', () => {
  const parts = state.currentPath.split('/').filter(Boolean);
  parts.pop();
  listDir(parts.join('/'));
});

elBtnNewFolder.addEventListener('click', () => {
  showModal(`
    <h2>New Folder</h2>
    <label for="m-name">Folder name</label>
    <input type="text" id="m-name" placeholder="New Folder" autocomplete="off" />
    <div class="modal-actions">
      <button class="btn btn-secondary" id="m-cancel">Cancel</button>
      <button class="btn btn-primary" id="m-confirm">Create</button>
    </div>
  `);
  const nameInput = document.getElementById('m-name');
  const cancel = document.getElementById('m-cancel');
  const confirm = document.getElementById('m-confirm');
  cancel.onclick = hideModal;
  const doCreate = async () => {
    const name = nameInput.value.trim();
    if (!name) return;
    hideModal();
    setLoading(true);
    try {
      const newPath = state.currentPath ? state.currentPath + '/' + name : name;
      await sendRequest('createDirectory', { path: newPath });
      toast('Folder created', 'success');
      await listDir(state.currentPath);
    } catch (err) {
      toast('Failed to create folder: ' + err.message, 'error');
    } finally {
      setLoading(false);
    }
  };
  confirm.onclick = doCreate;
  nameInput.addEventListener('keydown', e => { if (e.key === 'Enter') doCreate(); });
  setTimeout(() => nameInput.focus(), 50);
});

elBtnUpload.addEventListener('click', () => elFileInput.click());

elFileInput.addEventListener('change', async () => {
  const files = Array.from(elFileInput.files);
  if (!files.length) return;
  toast(`Uploading ${files.length} file${files.length > 1 ? 's' : ''}…`, 'info');
  setLoading(true);
  for (const f of files) await uploadFile(f);
  elFileInput.value = '';
  await listDir(state.currentPath);
  setLoading(false);
});

